import React, { useState } from 'react';
import SimpleImageUpload from './components/SimpleImageUpload';
import { predictInsect } from './services/api';

const SimpleApp = () => {
  const [selectedImage, setSelectedImage] = useState(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [result, setResult] = useState(null);

  const handleImageSelect = (imageData, file) => {
    console.log('Image selected:', file.name);
    setSelectedImage({ imageData, file });
    setResult(null);
  };

  const handleImageRemove = () => {
    console.log('Image removed');
    setSelectedImage(null);
    setResult(null);
  };

  const handleAnalyze = async () => {
    if (!selectedImage) {
      alert('Vui lòng chọn ảnh trước khi phân tích');
      return;
    }

    console.log('Starting analysis...');
    setIsAnalyzing(true);
    try {
      const result = await predictInsect(selectedImage.file);
      console.log('Analysis result:', result);
      setResult(result);
    } catch (error) {
      console.error('Analysis error:', error);
      alert('Có lỗi xảy ra khi phân tích ảnh: ' + error.message);
    } finally {
      setIsAnalyzing(false);
    }
  };

  return (
    <div style={{
      minHeight: '100vh',
      background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
      padding: '20px'
    }}>
      <div style={{
        maxWidth: '1200px',
        margin: '0 auto',
        background: 'white',
        borderRadius: '20px',
        padding: '40px',
        boxShadow: '0 25px 50px -12px rgb(0 0 0 / 0.25)'
      }}>
        <h1 style={{
          textAlign: 'center',
          fontSize: '2.5rem',
          fontWeight: '800',
          marginBottom: '20px',
          color: '#262626'
        }}>
          🐛 NhanDienSauHai AI
        </h1>

        <p style={{
          textAlign: 'center',
          fontSize: '1.2rem',
          color: '#525252',
          marginBottom: '40px'
        }}>
          Ứng dụng thông minh giúp nông dân nhận diện sâu hại
        </p>

        <SimpleImageUpload
          onImageSelect={handleImageSelect}
          onImageRemove={handleImageRemove}
          selectedImage={selectedImage?.imageData}
        />

        {selectedImage && (
          <div style={{ textAlign: 'center', marginTop: '30px' }}>
            <button
              onClick={handleAnalyze}
              disabled={isAnalyzing}
              style={{
                background: isAnalyzing ? '#9ca3af' : 'linear-gradient(135deg, #22c55e 0%, #16a34a 100%)',
                color: 'white',
                border: 'none',
                padding: '16px 40px',
                borderRadius: '9999px',
                fontSize: '18px',
                fontWeight: '600',
                cursor: isAnalyzing ? 'not-allowed' : 'pointer',
                display: 'flex',
                alignItems: 'center',
                gap: '10px',
                margin: '0 auto'
              }}
            >
              {isAnalyzing ? (
                <>
                  <div style={{
                    width: '20px',
                    height: '20px',
                    border: '2px solid currentColor',
                    borderTop: '2px solid transparent',
                    borderRadius: '50%',
                    animation: 'spin 1s linear infinite'
                  }} />
                  Đang phân tích...
                </>
              ) : (
                <>
                  🧠 Phân tích ảnh
                </>
              )}
            </button>
          </div>
        )}

        {result && (
          <div style={{
            marginTop: '30px',
            padding: '20px',
            background: '#f0fdf4',
            borderRadius: '12px',
            border: '1px solid #bbf7d0'
          }}>
            <h3 style={{ color: '#15803d', marginBottom: '15px' }}>
              ✅ Kết quả phân tích:
            </h3>
            <pre style={{
              background: 'white',
              padding: '15px',
              borderRadius: '8px',
              overflow: 'auto',
              fontSize: '14px'
            }}>
              {JSON.stringify(result, null, 2)}
            </pre>
          </div>
        )}

        <div style={{
          marginTop: '40px',
          textAlign: 'center',
          padding: '20px',
          background: '#f8fafc',
          borderRadius: '12px'
        }}>
          <h3 style={{ color: '#374151', marginBottom: '15px' }}>
            📊 Thống kê hệ thống
          </h3>
          <div style={{ display: 'flex', justifyContent: 'center', gap: '30px', flexWrap: 'wrap' }}>
            <div>
              <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#22c55e' }}>102</div>
              <div style={{ color: '#6b7280' }}>Loài sâu hại</div>
            </div>
            <div>
              <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#3b82f6' }}>95%</div>
              <div style={{ color: '#6b7280' }}>Độ chính xác</div>
            </div>
            <div>
              <div style={{ fontSize: '2rem', fontWeight: 'bold', color: '#f59e0b' }}>24/7</div>
              <div style={{ color: '#6b7280' }}>Hỗ trợ</div>
            </div>
          </div>
        </div>
      </div>

      <style>{`
        @keyframes spin {
          0% { transform: rotate(0deg); }
          100% { transform: rotate(360deg); }
        }
      `}</style>
    </div>
  );
};

export default SimpleApp;
